Pytest tests for leave request submission requirement:
- Full-time employees can submit leave requests for 1 to 30 business days.
- Requests spanning more than 30 business days require hr-admin approval.
"""

import pytest
from unittest.mock import MagicMock, patch

# ---------------------------------------------------------------------------
# Assumption: the production code exposes an interface similar to the one
# below.  Adjust the import paths to match your actual module structure.
#
#   from leave_management.service import LeaveRequestService
#   from leave_management.models import Employee, EmploymentType, LeaveRequest
