# ---------------------------------------------------------------------------
from leave_management.service import LeaveRequestService
from leave_management.models import Employee, EmploymentType, LeaveRequest
from leave_management.exceptions import (
    InvalidLeaveDurationError,
    UnauthorizedLeaveRequestError,
    ApprovalRequiredError,
)


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def full_time_employee():
    """A standard full-time employee."""
    return Employee(
        employee_id="EMP001",
        name="Jane Doe",
        employment_type=EmploymentType.FULL_TIME,
    )


@pytest.fixture
def part_time_employee():
    """A part-time employee (not entitled to use this workflow)."""
    return Employee(
        employee_id="EMP002",
        name="John Smith",
        employment_type=EmploymentType.PART_TIME,
    )


@pytest.fixture
def hr_admin_employee():
    """An HR-admin employee."""
    return Employee(
        employee_id="HR001",
        name="Alice Admin",
        employment_type=EmploymentType.FULL_TIME,
        is_hr_admin=True,
    )


@pytest.fixture
def leave_service():
    """LeaveRequestService with a mocked repository and approval gateway."""
    repo = MagicMock()
    approval_gateway = MagicMock()
    return LeaveRequestService(repository=repo, approval_gateway=approval_gateway)


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def make_request(employee, business_days, approved_by=None):
    """Convenience wrapper to build a LeaveRequest domain object."""
    return LeaveRequest(
        employee=employee,
        business_days=business_days,
        approved_by=approved_by,
    )


# ===========================================================================
# 1. VALID SUBMISSIONS — 1 to 30 business days
# ===========================================================================

class TestValidLeaveRequestSubmission:
    """Full-time employees can submit requests for 1–30 business days."""

    @pytest.mark.parametrize("days", [1, 2, 15, 29, 30])
    def test_submit_valid_duration_returns_request(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)
        result = leave_service.submit(request)

        assert result is not None
        assert isinstance(result, LeaveRequest)

    @pytest.mark.parametrize("days", [1, 2, 15, 29, 30])
    def test_submit_valid_duration_persists_request(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)
        leave_service.submit(request)

        leave_service.repository.save.assert_called_once_with(request)

    @pytest.mark.parametrize("days", [1, 30])
    def test_boundary_days_do_not_trigger_approval_workflow(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)
        leave_service.submit(request)

        leave_service.approval_gateway.request_approval.assert_not_called()

    def test_single_day_request_is_accepted(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=1)
        result = leave_service.submit(request)

        assert result.status == "SUBMITTED"

    def test_thirty_day_request_is_accepted(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=30)
        result = leave_service.submit(request)

        assert result.status == "SUBMITTED"


# ===========================================================================
# 2. INVALID DURATIONS — below minimum or above maximum without approval
# ===========================================================================

class TestInvalidLeaveDuration:
    """Requests outside the 1–30 day window without approval must be rejected."""

    @pytest.mark.parametrize("days", [0, -1, -10])
    def test_zero_or_negative_days_raises_invalid_duration(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)

        with pytest.raises(InvalidLeaveDurationError):
            leave_service.submit(request)

    @pytest.mark.parametrize("days", [0, -1])
    def test_invalid_duration_does_not_persist(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)

        with pytest.raises(InvalidLeaveDurationError):
            leave_service.submit(request)

        leave_service.repository.save.assert_not_called()

    def test_thirty_one_days_without_approval_raises_approval_required(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=31)

        with pytest.raises(ApprovalRequiredError):
            leave_service.submit(request)

    @pytest.mark.parametrize("days", [31, 45, 60, 365])
    def test_over_thirty_days_without_approval_raises_approval_required(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)

        with pytest.raises(ApprovalRequiredError):
            leave_service.submit(request)

    @pytest.mark.parametrize("days", [31, 60])
    def test_over_thirty_days_does_not_persist_without_approval(
        self, leave_service, full_time_employee, days
    ):
        request = make_request(full_time_employee, business_days=days)

        with pytest.raises(ApprovalRequiredError):
            leave_service.submit(request)

        leave_service.repository.save.assert_not_called()

    def test_non_integer_duration_raises_invalid_duration(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=2.5)

        with pytest.raises(InvalidLeaveDurationError):
            leave_service.submit(request)

    def test_none_duration_raises_invalid_duration(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=None)

        with pytest.raises(InvalidLeaveDurationError):
            leave_service.submit(request)


# ===========================================================================
# 3. HR-ADMIN APPROVAL PATH — more than 30 business days
# ===========================================================================

class TestHrAdminApprovalForLongRequests:
    """Requests > 30 business days require explicit hr-admin approval."""

    @pytest.mark.parametrize("days", [31, 45, 60])
    def test_submit_with_hr_admin_approval_is_accepted(
        self, leave_service, full_time_employee, hr_admin_employee, days
    ):
        request = make_request(
            full_time_employee,
            business_days=days,
            approved_by=hr_admin_employee,
        )
        result = leave_service.submit(request)

        assert result is not None

    @pytest.mark.parametrize("days", [31, 60])
    def test_submit_with_hr_admin_approval_persists_request(
        self, leave_service, full_time_employee, hr_admin_employee, days
    ):
        request = make_request(
            full_time_employee,
            business_days=days,
            approved_by=hr_admin_employee,
        )
        leave_service.submit(request)

        leave_service.repository.save.assert_called_once_with(request)

    @pytest.mark.parametrize("days", [31, 45])
    def test_submit_with_hr_admin_approval_status_is_approved(
        self, leave_service, full_time_employee, hr_admin_employee, days
    ):
        request = make_request(
            full_time_employee,
            business_days=days,
            approved_by=hr_admin_employee,
        )
        result = leave_service.submit(request)

        assert result.status == "HR_APPROVED"

    def test_thirty_one_days_approved_by_non_admin_raises_unauthorized(
        self, leave_service, full_time_employee
    ):
        non_admin = Employee(
            employee_id="EMP003",
            name="Bob Regular",
            employment_type=EmploymentType.FULL_TIME,
            is_hr_admin=False,
        )
        request = make_request(
            full_time_employee,
            business_days=31,
            approved_by=non_admin,
        )

        with pytest.raises(UnauthorizedLeaveRequestError):
            leave_service.submit(request)

    def test_approval_required_error_message_mentions_hr_admin(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=31)

        with pytest.raises(ApprovalRequiredError) as exc_info:
            leave_service.submit(request)

        assert "hr-admin" in str(exc_info.value).lower()

    def test_approval_required_error_includes_requested_days(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=45)

        with pytest.raises(ApprovalRequiredError) as exc_info:
            leave_service.submit(request)

        assert "45" in str(exc_info.value)


# ===========================================================================
# 4. EMPLOYMENT TYPE GUARD — only full-time employees may use this workflow
# ===========================================================================

class TestEmploymentTypeRestriction:
    """Only full-time employees are entitled to submit leave via this service."""

    def test_part_time_employee_cannot_submit_leave(
        self, leave_service, part_time_employee
    ):
        request = make_request(part_time_employee, business_days=5)

        with pytest.raises(UnauthorizedLeaveRequestError):
            leave_service.submit(request)

    def test_part_time_employee_request_does_not_persist(
        self, leave_service, part_time_employee
    ):
        request = make_request(part_time_employee, business_days=5)

        with pytest.raises(UnauthorizedLeaveRequestError):
            leave_service.submit(request)

        leave_service.repository.save.assert_not_called()

    def test_unauthorized_error_message_mentions_full_time(
        self, leave_service, part_time_employee
    ):
        request = make_request(part_time_employee, business_days=5)

        with pytest.raises(UnauthorizedLeaveRequestError) as exc_info:
            leave_service.submit(request)

        assert "full-time" in str(exc_info.value).lower()

    def test_no_employee_raises_unauthorized(self, leave_service):
        request = make_request(employee=None, business_days=5)

        with pytest.raises(UnauthorizedLeaveRequestError):
            leave_service.submit(request)


# ===========================================================================
# 5. EDGE / BOUNDARY CASES
# ===========================================================================

class TestEdgeCases:
    """Boundary and edge-case scenarios."""

    def test_exactly_one_day_is_minimum_valid(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=1)
        result = leave_service.submit(request)

        assert result.business_days == 1

    def test_exactly_thirty_days_is_maximum_without_approval(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=30)
        result = leave_service.submit(request)

        assert result.business_days == 30

    def test_thirty_one_days_is_minimum_requiring_approval(
        self, leave_service, full_time_employee, hr_admin_employee
    ):
        request = make_request(
            full_time_employee,
            business_days=31,
            approved_by=hr_admin_employee,
        )
        result = leave_service.submit(request)

        assert result.business_days == 31
        assert result.status == "HR_APPROVED"

    def test_employee_id_is_recorded_on_submitted_request(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=5)
        result = leave_service.submit(request)

        assert result.employee.employee_id == full_time_employee.employee_id

    def test_submitted_request_has_a_generated_id(
        self, leave_service, full_time_employee
    ):
        request = make_request(full_time_employee, business_days=5)
        result = leave_service.submit(request)

        assert result.request_id is not None

    @pytest.mark.parametrize("days", [1, 15, 30])
    def test_duplicate_submission_raises_or_returns_existing(
        self, leave_service, full_time_employee, days
    ):
        """Service must not silently create duplicate requests."""
        request = make_request(full_time_employee, business_days=days)
        leave_service.submit(request)

        # A second identical submission should either raise or return the
        # existing record — never silently create a duplicate.
        try:
            second_result = leave_service.submit(request)
            assert second_result.request_id == request.request_id, (
                "Duplicate submission must return the existing request"
            )
        except Exception:
            pass  # Raising is also an acceptable strategy
```

---

### Key design decisions

| Area | Decision |
|---|---|
| **Boundaries** | `1` and `30` are tested explicitly as valid; `0` and `31` are tested as the first invalid values on each side. |
| **Parametrize** | `@pytest.mark.parametrize` covers representative interior values so a single off-by-one bug surfaces quickly. |
| **Side-effect assertions** | Tests verify that the repository `.save()` is *not* called on failure paths, preventing silent data corruption. |
| **HR-admin approval** | Checked as a positive path (approval granted) *and* a negative path (non-admin tries to approve). |
| **Employment type** | Part-time and `None` employees are rejected before any business-day logic runs. |
| **Error messages** | Key phrases (`"hr-admin"`, `"full-time"`) are asserted so error messages stay human-readable and auditable. |

